insert into questionnaire_questions (id, question_order, question_kind, question_en, question_th, active) values ('q02', 2, 'scored', 'How do you feel about being tied up or restrained?', 'คุณรู้สึกอย่างไรเกี่ยวกับการถูกมัดหรือถูกจำกัดการเคลื่อนไหว?', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q02_a', 'q02', 1, 'A', 'Crave to be tightly bound, helpless, and completely at his mercy', 'ปรารถนาที่จะถูกมัดแน่น ไร้ซึ่งทางช่วยเหลือ และอยู่ภายใต้ความเมตตาของอีกฝ่ายอย่างสมบูรณ์', 3, 1, 1, -1, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q02_b', 'q02', 2, 'B', 'Tying, creating intricate rope work, and having them under my control is the best', 'การมัดผู้อื่น สร้างงานเชือกที่ซับซ้อน และควบคุมผู้อื่นให้อยู่ในอำนาจของฉันคือสิ่งที่ดีที่สุด', 2, -1, -1, 3, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q02_c', 'q02', 3, 'C', 'Being restrained can be exciting sometimes, but I prefer having the freedom to react, whether I''m the one being controlled or the one in control', 'การถูกจำกัดการเคลื่อนไหวบางครั้งก็น่าตื่นเต้น แต่ฉันชอบการมีอิสระในการตอบสนองมากกว่า ไม่ว่าจะเป็นการถูกควบคุมหรือเป็นฝ่ายควบคุมก็ตาม', -1, 2, 2, 2, null, null, null, null, true);
insert into questionnaire_questions (id, question_order, question_kind, question_en, question_th, active) values ('q03', 3, 'scored', 'What kind of power dynamic do you prefer?', 'คุณชื่นชอบบทบาทอำนาจแบบใดในความสัมพันธ์?', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q03_a', 'q03', 1, 'A', 'Fully surrender, serve, and be owned like a devoted slave, pet', 'การยอมจำนนอย่างสมบูรณ์ รับใช้ และถูกครอบครองเหมือนทาส สัตว์เลี้ยง', 1, 3, 1, -3, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q03_b', 'q03', 2, 'B', 'Own, command, and take full responsibility as a Master is great', 'การเป็นเจ้าของสั่งการและรับผิดชอบเต็มที่ในฐานะเจ้านาย คือสิ่งที่ยอดเยี่ยม', -2, -2, -2, 3, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q03_c', 'q03', 3, 'C', 'Power dynamic is not important for me as long as the experience is exciting.', 'บทบาทอำนาจไม่สำคัญสำหรับฉันตราบใดที่ประสบการณ์ที่ได้รับนั้นน่าตื่นเต้น', 2, -3, 2, -2, null, null, null, null, true);
insert into questionnaire_questions (id, question_order, question_kind, question_en, question_th, active) values ('q04', 4, 'scored', 'How do you feel about pain or intense physical sensations?', 'คุณรู้สึกอย่างไรเกี่ยวกับความเจ็บปวดหรือความรู้สึกทางกายภาพที่รุนแรง?', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q04_a', 'q04', 1, 'A', 'I enjoy pain, emotional intensity that pushes me to my limits, and even the lingering marks left behind by those experiences.', 'ฉันชื่นชอบความเจ็บปวด การถูกบีบคั้นทางอารมณ์ให้ถึงขีดจำกัด รวมถึงร่องรอยของความเจ็บปวดเหล่านั้นบนเรือนร่างของฉันด้วย', 1, 1, 3, -3, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q04_b', 'q04', 2, 'B', 'I enjoy being the one who inflicts pain and observing the other person''s reactions.', 'ฉันชอบเป็นฝ่ายสร้างความเจ็บปวดและดูปฏิกริยาของอีกฝ่าย', -1, -2, -2, 3, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q04_c', 'q04', 3, 'C', 'I prefer other forms of excitement over either giving or receiving pain.', 'ฉันชอบความตื่นเต้นในรูปแบบอื่นมากกว่าการสร้างหรือรับความเจ็บปวด', 2, 2, -3, -2, null, null, null, null, true);
