insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q06_b', 'q06', 2, 'B', 'Intermediate', 'ฉันมักจะลองประสบการณ์ที่เกี่ยวกับการยอมจำนน, ถูกมัด, หรือความเจ็บปวด', 3, 3, 3, -3, null, null, null, null, true);
