insert into questionnaire_questions (id, question_order, question_kind, question_en, question_th, active) values ('q07', 7, 'scored', 'Your opinion on consent', 'ทัศนคติของคุณเกี่ยวกับความสมยอม(consent)', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q07_a', 'q07', 1, 'A', 'Consent is absolute, non-negotiable.', 'เป็นสิ่งที่ต้องมีอย่างเด็ดขาด ยืดหยุ่นไม่ได้', 3, 1, 3, 1, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q07_b', 'q07', 2, 'B', 'Pushing boundary and consent is what make thing spicy.', 'เป็นสิ่งที่ยืดหยุ่นได้ การต่อรองหรือผลักเส้นความสมยอมนิดๆ หน่อย ๆ เป็นเรื่องน่าสนุก', -3, -3, -3, -3, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q07_c', 'q07', 3, 'C', 'There’s nothing money and power cannot buy, including consent.', 'ความสมยอม? ไม่มีอะไรที่เงินและอำนาจซื้อไม่ได้หรอก', 0, 0, 0, 0, 'too_young', null, 'Is that truly what you believe? Then I am afraid our club may not be the place for you, sweetheart.', 'นั่นคือสิ่งที่คุณเชื่อจริง ๆ หรือ? ถ้าอย่างนั้นฉันเกรงว่าคลับของเราอาจไม่ใช่สถานที่สำหรับคุณนะที่รัก', true);
insert into questionnaire_questions (id, question_order, question_kind, question_en, question_th, active) values ('q08', 8, 'scored', 'Do you enjoy initiating conversations with strangers?', 'คุณชอบเป็นคนเริ่มบทสนทนากับคนแปลกหน้า', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q08_a', 'q08', 1, 'A', 'yes, I like to initiate conversations with strangers.', 'ใช่ ฉันชอบเริ่มบทสนทนาก่อน', 3, -1, 2, 1, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q08_b', 'q08', 2, 'B', 'It depends on the situation.', 'แล้วแต่สถานการณ์', 3, 1, 2, 1, null, null, null, null, true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q08_c', 'q08', 3, 'C', 'I don''t know how to start conversations', 'ฉันไม่รู้จะเริ่มบทสนทนาก่อนอย่างไร', 2, 1, 3, -1, null, null, null, null, true);
insert into questionnaire_questions (id, question_order, question_kind, question_en, question_th, active) values ('q09', 9, 'scored', 'If you encounter an activity you don''t want to do, you should...', 'หากคุณเจอกับกิจกรรมที่ไม่ต้องการ คุณควรจะ', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q09_a', 'q09', 1, 'A', 'Be patient for the host''s pleasure.', 'อดทนเพื่อความพึงพอใจของโฮสต์', 0, 0, 0, 0, 'too_young', null, 'Though it is rather adorable, that is not what you should do. Pleasure belongs to both of us. Try reviewing the rules again, sweetheart.', 'แม้ว่าจะน่าเอ็นดู แต่นั่นไม่ใช่สิ่งที่คุณควรทำ ความพึงพอใจเป็นของพวกเราทั้งสองฝ่าย ลองกลับไปทบทวนกฏใหม่ก่อนนะที่รัก', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q09_b', 'q09', 2, 'B', 'How Dare You!', 'กล้าดียังไง!', 0, 0, 0, 0, 'too_young', null, 'Sweetheart, that is exactly why we use safe words and safe gestures. Take a moment to calm yourself, then read the rules again.', 'ที่รัก เรามีการใช้ safe word และ safe gesture เพื่อการนี้ ลองสงบสติอารมณ์แล้วกลับไปอ่านกฏดูอีกครั้ง', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q09_c', 'q09', 3, 'C', 'Use a safe word or safe gesture to stop all activity.', 'ใช้ safe word หรือ safe gesture เพื่อหยุดทุกกิจกรรม', 0, 0, 0, 0, null, null, null, null, true);
insert into questionnaire_questions (id, question_order, question_kind, question_en, question_th, active) values ('q10', 10, 'scored', 'What is most important for a club member''s promotion?', 'สิ่งใดสำคัญที่สุดในการเลื่อนขั้นของสมาชิกคลับ', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q10_a', 'q10', 1, 'A', 'Money', 'เงิน', 0, 0, 0, 0, 'too_young', null, 'Money is something you need to enter the club, but it is not the most important thing when it comes to ranking up. Think carefully, sweetheart. Did you forget something in our rules?', 'เงินเป็นสิ่งที่คุณจำเป็นต้องมีในการเข้าคลับ แต่นั่นไม่ใช่สิ่งที่สำคัญที่สุดในการเลื่อนขั้น นึกดูดี ๆ ที่รัก คุณลืมอะไรไปในกฏกติกาของเราหรือเปล่า', true);
insert into questionnaire_choices (id, question_id, choice_order, label, choice_en, choice_th, score_b, score_d, score_s, score_m, special_action, special_url, feedback_en, feedback_th, active) values ('q10_b', 'q10', 2, 'B', 'Power', 'อำนาจ', 0, 0, 0, 0, 'too_young', null, 'Power is not something you can use to rank up here. If you still do not understand that, try reviewing the rules again, sweetheart.', 'อำนาจไม่ใช่สิ่งที่คุณจะใช้สำหรับการเลื่อนขั้นที่นี่ได้ ถ้าคุณยังไม่เข้าใจตรงนี้ ลองกลับไปทบทวนกฏดูอีกครั้งนะที่รัก', true);
